package com.example.btl.Api

import com.example.btl.Model.AddToCartRequest
import com.example.btl.Model.Cart
import com.example.btl.Model.CartItem
import com.example.btl.Model.CreateCartRequest
import com.example.btl.Model.UpdateCartItemsRequest
import com.example.btl.Model.UpdateCartRequest
import retrofit2.Response
import retrofit2.http.Body
import retrofit2.http.DELETE
import retrofit2.http.GET
import retrofit2.http.Header
import retrofit2.http.POST
import retrofit2.http.PUT
import retrofit2.http.Path

interface CartApi {
    /**
     * GET /carts/:id - Lấy cart của customer theo customer_id
     * Returns: Cart object với nested cart_items array
     */
    @GET("carts/{customerId}")
    suspend fun getCart(
        @Path("customerId") customerId: Int,
        @Header("Authorization") token: String
    ): Response<Cart>

    /**
     * POST /carts/add - Thêm item vào cart (backend endpoint)
     * Input: AddToCartRequest với customer_id và variant_id (flat format)
     * Returns: Empty body (backend doesn't return data)
     * Note: Client should use GET /carts/{customerId} to fetch updated cart
     */
    @POST("carts/add")
    suspend fun addToCart(
        @Body request: AddToCartRequest,
        @Header("Authorization") token: String
    ): Response<Void>

    /**
     * POST /carts - Tạo cart mới (fallback/legacy endpoint)
     * Input: CreateCartRequest với customer_id và items array
     * Returns: Cart object mới tạo
     */
    @POST("carts")
    suspend fun createCart(
        @Body request: CreateCartRequest,
        @Header("Authorization") token: String
    ): Response<Cart>

    /**
     * PUT /carts/:id - Update cart (update cart items)
     * Input: UpdateCartItemsRequest với items array
     * Returns: Updated Cart object
     */
    @PUT("carts/{id}")
    suspend fun updateCart(
        @Path("id") cartId: Int,
        @Body request: UpdateCartItemsRequest,
        @Header("Authorization") token: String
    ): Response<Cart>

    /**
     * PUT /carts/item/:id - Update quantity của 1 cart item
     * Input: UpdateCartRequest với quantity
     * Returns: Updated CartItem object
     */
    @PUT("carts/item/{id}")
    suspend fun updateCartItem(
        @Path("id") cartItemId: Int,
        @Body request: UpdateCartRequest,
        @Header("Authorization") token: String
    ): Response<CartItem>

    /**
     * DELETE /carts/item/:id - Xóa 1 item từ cart
     * Returns: success message hoặc updated Cart
     */
    @DELETE("carts/item/{id}")
    suspend fun deleteCartItem(
        @Path("id") cartItemId: Int,
        @Header("Authorization") token: String
    ): Response<Cart>
}

package com.example.btl.Api

import com.example.btl.Model.AddToCartRequest
import com.example.btl.Model.Cart
import com.example.btl.Model.CartItem
