    ): Response<CartItem>

    /**
     * DELETE /carts/item/:id - Xóa 1 item từ cart
     * Returns: success message hoặc updated Cart
     */
    @DELETE("carts/item/{id}")
    suspend fun deleteCartItem(
        @Path("id") cartItemId: Int,
