package com.example.btl.Repository

import android.util.Log
import com.example.btl.Api.CartApi
import com.example.btl.Api.RetrofitClient
import com.example.btl.Model.AddToCartRequest
import com.example.btl.Model.Cart
import com.example.btl.Model.CartItem
import com.example.btl.Model.CartItemRequest
import com.example.btl.Model.CreateCartRequest
import com.example.btl.Model.UpdateCartItemRequest
import com.example.btl.Model.UpdateCartItemsRequest
import com.example.btl.Model.UpdateCartRequest

class CartRepository {
    private val cartApi: CartApi = RetrofitClient.cartApi
    private val TAG = "CartRepository"

    /**
     * Lấy cart của customer hiện tại
     */
    suspend fun getCart(customerId: Int, token: String): Result<Cart> = try {
        Log.d(TAG, "getCart: Calling API for customer $customerId")
        val response = cartApi.getCart(customerId, "Bearer $token")
        Log.d(TAG, "getCart: Response code=${response.code()}")

        if (response.isSuccessful) {
            val cart = response.body() ?: Cart()
            Log.d(TAG, "getCart: ✅ Success - ${cart.cart_items.size} items in cart")
            Result.success(cart)
        } else {
            Log.e(TAG, "getCart: ❌ Error ${response.code()} - ${response.message()}")
            Result.failure(Exception("Error: ${response.code()} - ${response.message()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "getCart: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }

    /**
     * Tạo cart mới với items (POST)
     * Sau đó tự động GET cart để lấy dữ liệu mới nhất
     */
    suspend fun createCart(
        customerId: Int? = null,
        items: List<CartItemRequest>? = null,
        token: String
    ): Result<Cart> = try {
        Log.d(TAG, "createCart: Creating new cart")
        val request = CreateCartRequest(
            customer_id = customerId,
            items = items ?: emptyList()
        )

        // Step 1: POST - Tạo/thêm item vào cart
        val response = cartApi.createCart(request, "Bearer $token")
        Log.d(TAG, "createCart: POST Response code=${response.code()}")

        if (response.isSuccessful) {
            val cart = response.body() ?: Cart()
            Log.d(TAG, "createCart: ✅ POST Success - Cart created with ${cart.cart_items.size} items")

            // Step 2: GET - Lấy cart mới nhất từ server
            if (customerId != null) {
                Log.d(TAG, "createCart: Fetching updated cart from server")
                val getResponse = cartApi.getCart(customerId, "Bearer $token")
                if (getResponse.isSuccessful) {
                    val updatedCart = getResponse.body() ?: cart
                    Log.d(TAG, "createCart: ✅ GET Success - Got ${updatedCart.cart_items.size} items")
                    Result.success(updatedCart)
                } else {
                    Log.w(TAG, "createCart: GET failed, returning POST result")
                    Result.success(cart)
                }
            } else {
                Result.success(cart)
            }
        } else {
            Log.e(TAG, "createCart: ❌ Error ${response.code()}")
            Result.failure(Exception("Error: ${response.code()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "createCart: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }

    /**
     * Add to cart - Thêm 1 sản phẩm vào cart (endpoint /carts/add)
     * Backend format: { customer_id, variant_id, render_id? }
     * Returns: CartItem từ backend, sau đó sync với GET /carts/{customerId}
     * 
     * ✅ Support guest users (customer_id = null)
     * ✅ Support mockup renders (render_id)
     */
    suspend fun addToCart(
        customerId: Int?,    // ✅ Allow null for guest users
        variantId: Int,
        token: String,
        renderId: Int? = null  // ✅ Support mockup renders
    ): Result<Cart> = try {
        Log.d(TAG, "addToCart: Adding item - customer=$customerId, variant=$variantId, render=$renderId")

        // Build request cho /carts/add endpoint
        val request = AddToCartRequest(
            customer_id = customerId,  // ✅ Can be null
            variant_id = variantId,
            render_id = renderId       // ✅ Add render_id
        )

        // Step 1: POST /carts/add - Add item to cart
        val response = cartApi.addToCart(request, "Bearer $token")
        Log.d(TAG, "addToCart: POST /carts/add - Response code=${response.code()}")

        if (response.isSuccessful) {
            Log.d(TAG, "addToCart: ✅ POST Success - Response code=${response.code()}")

            // ✅ ADD: Check if response body exists
            val responseBody = response.body()
            if (responseBody == null) {
                Log.w(TAG, "addToCart: ⚠️ Response successful but body is NULL!")
                Log.w(TAG, "addToCart: This suggests backend /carts/add endpoint not returning data")
                // Return empty cart as fallback - backend issue
                return Result.success(Cart(customer_id = customerId))
            }

            Log.d(TAG, "addToCart: ✅ POST Success")

            // Step 2: GET /carts/{customerId} - Fetch updated cart from server
            // ✅ Handle guest users: customerId might be null, so only fetch if available
            if (customerId != null) {
                Log.d(TAG, "addToCart: Fetching updated cart from server")
                val getResponse = cartApi.getCart(customerId, "Bearer $token")
                if (getResponse.isSuccessful) {
                    val cart = getResponse.body() ?: Cart()
                    Log.d(TAG, "addToCart: ✅ GET Success - Cart has ${cart.cart_items.size} items")
                    Result.success(cart)
                } else {
                    Log.w(TAG, "addToCart: GET failed after POST success")
                    // Return empty cart as fallback
                    Result.success(Cart(customer_id = customerId))
                }
            } else {
                // Guest user: return empty cart
                Log.d(TAG, "addToCart: Guest user - returning empty cart")
                Result.success(Cart(customer_id = null))
            }
        } else {
            Log.e(TAG, "addToCart: ❌ Error ${response.code()} - ${response.message()}")
            Result.failure(Exception("Error: ${response.code()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "addToCart: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }

    /**
     * Update cart với items mới
     */
    suspend fun updateCart(
        cartId: Int,
        cartItems: List<UpdateCartItemRequest>,
        token: String
    ): Result<Cart> = try {
        Log.d(TAG, "updateCart: Updating cart $cartId with ${cartItems.size} items")
        val request = UpdateCartItemsRequest(items = cartItems)

        val response = cartApi.updateCart(cartId, request, "Bearer $token")
        Log.d(TAG, "updateCart: Response code=${response.code()}")

        if (response.isSuccessful) {
            val cart = response.body() ?: Cart()
            Log.d(TAG, "updateCart: ✅ Success")
            Result.success(cart)
        } else {
            Log.e(TAG, "updateCart: ❌ Error ${response.code()}")
            Result.failure(Exception("Error: ${response.code()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "updateCart: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }

    /**
     * Update quantity của 1 cart item (PUT /carts/item/{id})
     * Gửi PUT request và auto-fetch full cart để sync
     */
    suspend fun updateCartItemQuantity(
        cartItemId: Int,
        quantity: Int,
        customerId: Int,
        token: String
    ): Result<Cart> = try {
        Log.d(TAG, "updateCartItemQuantity: Updating item $cartItemId to quantity $quantity")
        val request = UpdateCartRequest(
            cart_item_id = cartItemId,
            quantity = quantity
        )

        // Step 1: PUT /carts/item/{id} - Update quantity
        val response = cartApi.updateCartItem(cartItemId, request, "Bearer $token")
        Log.d(TAG, "updateCartItemQuantity: PUT Response code=${response.code()}")

        if (response.isSuccessful) {
            Log.d(TAG, "updateCartItemQuantity: ✅ PUT Success - Item updated to quantity $quantity")

            // Step 2: GET /carts/{customerId} - Fetch updated cart
            Log.d(TAG, "updateCartItemQuantity: Fetching updated cart from server")
            val getResponse = cartApi.getCart(customerId, "Bearer $token")
            if (getResponse.isSuccessful) {
                val cart = getResponse.body() ?: Cart()
                Log.d(TAG, "updateCartItemQuantity: ✅ GET Success - Cart has ${cart.cart_items.size} items")
                Result.success(cart)
            } else {
                Log.w(TAG, "updateCartItemQuantity: GET failed after PUT success")
                // Return empty cart as fallback
                Result.success(Cart(customer_id = customerId))
            }
        } else {
            Log.e(TAG, "updateCartItemQuantity: ❌ Error ${response.code()}")
            Result.failure(Exception("Error: ${response.code()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "updateCartItemQuantity: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }

    /**
     * Xóa 1 item từ cart (DELETE /carts/item/{id})
     * Sau đó auto-fetch full cart để sync
     */
    suspend fun deleteCartItem(
        cartItemId: Int,
        customerId: Int,
        token: String
    ): Result<Cart> = try {
        Log.d(TAG, "deleteCartItem: Deleting cart item $cartItemId")
        val response = cartApi.deleteCartItem(cartItemId, "Bearer $token")
        Log.d(TAG, "deleteCartItem: DELETE Response code=${response.code()}")

        if (response.isSuccessful) {
            Log.d(TAG, "deleteCartItem: ✅ DELETE Success")

            // Step 2: GET /carts/{customerId} - Fetch updated cart
            Log.d(TAG, "deleteCartItem: Fetching updated cart from server")
            val getResponse = cartApi.getCart(customerId, "Bearer $token")
            if (getResponse.isSuccessful) {
                val cart = getResponse.body() ?: Cart()
                Log.d(TAG, "deleteCartItem: ✅ GET Success - Cart has ${cart.cart_items.size} items")
                Result.success(cart)
            } else {
                Log.w(TAG, "deleteCartItem: GET failed after DELETE success")
                // Return empty cart as fallback
                Result.success(Cart(customer_id = customerId))
            }
        } else {
            Log.e(TAG, "deleteCartItem: ❌ Error ${response.code()}")
            Result.failure(Exception("Error: ${response.code()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "deleteCartItem: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }
}

package com.example.btl.Repository

import android.util.Log
import com.example.btl.Api.CartApi
import com.example.btl.Api.RetrofitClient
import com.example.btl.Model.AddToCartRequest
import com.example.btl.Model.Cart
import com.example.btl.Model.CartItem
import com.example.btl.Model.CartItemRequest
import com.example.btl.Model.CreateCartRequest
import com.example.btl.Model.UpdateCartItemRequest
import com.example.btl.Model.UpdateCartItemsRequest
import com.example.btl.Model.UpdateCartRequest

class CartRepository {
    private val cartApi: CartApi = RetrofitClient.cartApi
    private val TAG = "CartRepository"

    /**
     * Lấy cart của customer hiện tại
     */
    suspend fun getCart(customerId: Int, token: String): Result<Cart> = try {
        Log.d(TAG, "getCart: Calling API for customer $customerId")
        val response = cartApi.getCart(customerId, "Bearer $token")
        Log.d(TAG, "getCart: Response code=${response.code()}")

        if (response.isSuccessful) {
            val cart = response.body() ?: Cart()
            Log.d(TAG, "getCart: ✅ Success - ${cart.cart_items.size} items in cart")
            Result.success(cart)
        } else {
            Log.e(TAG, "getCart: ❌ Error ${response.code()} - ${response.message()}")
            Result.failure(Exception("Error: ${response.code()} - ${response.message()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "getCart: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }

    /**
     * Tạo cart mới với items (POST)
     * Sau đó tự động GET cart để lấy dữ liệu mới nhất
     */
    suspend fun createCart(
        customerId: Int? = null,
        items: List<CartItemRequest>? = null,
        token: String
    ): Result<Cart> = try {
        Log.d(TAG, "createCart: Creating new cart")
        val request = CreateCartRequest(
            customer_id = customerId,
            items = items ?: emptyList()
        )

        // Step 1: POST - Tạo/thêm item vào cart
        val response = cartApi.createCart(request, "Bearer $token")
        Log.d(TAG, "createCart: POST Response code=${response.code()}")

        if (response.isSuccessful) {
            val cart = response.body() ?: Cart()
            Log.d(TAG, "createCart: ✅ POST Success - Cart created with ${cart.cart_items.size} items")

            // Step 2: GET - Lấy cart mới nhất từ server
            if (customerId != null) {
                Log.d(TAG, "createCart: Fetching updated cart from server")
                val getResponse = cartApi.getCart(customerId, "Bearer $token")
                if (getResponse.isSuccessful) {
                    val updatedCart = getResponse.body() ?: cart
                    Log.d(TAG, "createCart: ✅ GET Success - Got ${updatedCart.cart_items.size} items")
                    Result.success(updatedCart)
                } else {
                    Log.w(TAG, "createCart: GET failed, returning POST result")
                    Result.success(cart)
                }
            } else {
                Result.success(cart)
            }
        } else {
            Log.e(TAG, "createCart: ❌ Error ${response.code()}")
            Result.failure(Exception("Error: ${response.code()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "createCart: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }

    /**
     * Add to cart - Thêm 1 sản phẩm vào cart (endpoint /carts/add)
     * Backend format: { customer_id, variant_id, render_id? }
     * Returns: CartItem từ backend, sau đó sync với GET /carts/{customerId}
     * 
     * ✅ Support guest users (customer_id = null)
     * ✅ Support mockup renders (render_id)
     */
    suspend fun addToCart(
        customerId: Int?,    // ✅ Allow null for guest users
        variantId: Int,
        token: String,
        renderId: Int? = null  // ✅ Support mockup renders
    ): Result<Cart> {
        return try {
            Log.d(TAG, "addToCart: Adding item - customer=$customerId, variant=$variantId, render=$renderId")

            // Build request cho /carts/add endpoint
            val request = AddToCartRequest(
                customer_id = customerId,  // ✅ Can be null
                variant_id = variantId,
                render_id = renderId       // ✅ Add render_id
            )

            // Step 1: POST /carts/add - Add item to cart
            val response = cartApi.addToCart(request, "Bearer $token")
            Log.d(TAG, "addToCart: POST /carts/add - Response code=${response.code()}")

            if (response.isSuccessful) {
                Log.d(TAG, "addToCart: ✅ POST Success - Response code=${response.code()}")

                // ✅ ADD: Check if response body exists
                val responseBody = response.body()
                if (responseBody == null) {
                    Log.w(TAG, "addToCart: ⚠️ Response successful but body is NULL!")
                    Log.w(TAG, "addToCart: This suggests backend /carts/add endpoint not returning data")
                    // Return empty cart as fallback - backend issue
                    return@try Result.success(Cart(customer_id = customerId))
                }

                Log.d(TAG, "addToCart: ✅ POST Success")

                // Step 2: GET /carts/{customerId} - Fetch updated cart from server
                // ✅ Handle guest users: customerId might be null, so only fetch if available
                if (customerId != null) {
                    Log.d(TAG, "addToCart: Fetching updated cart from server")
                    val getResponse = cartApi.getCart(customerId, "Bearer $token")
                    if (getResponse.isSuccessful) {
                        val cart = getResponse.body() ?: Cart()
                        Log.d(TAG, "addToCart: ✅ GET Success - Cart has ${cart.cart_items.size} items")
                        Result.success(cart)
                    } else {
                        Log.w(TAG, "addToCart: GET failed after POST success")
                        // Return empty cart as fallback
                        Result.success(Cart(customer_id = customerId))
                    }
                } else {
                    // Guest user: return empty cart
                    Log.d(TAG, "addToCart: Guest user - returning empty cart")
                    Result.success(Cart(customer_id = null))
                }
            } else {
                Log.e(TAG, "addToCart: ❌ Error ${response.code()} - ${response.message()}")
                Result.failure(Exception("Error: ${response.code()}"))
            }
        } catch (e: Exception) {
            Log.e(TAG, "addToCart: ❌ Exception - ${e.message}", e)
            Result.failure(e)
        }
    }

    /**
     * Update cart với items mới
     */
    suspend fun updateCart(
        cartId: Int,
        cartItems: List<UpdateCartItemRequest>,
        token: String
    ): Result<Cart> = try {
        Log.d(TAG, "updateCart: Updating cart $cartId with ${cartItems.size} items")
        val request = UpdateCartItemsRequest(items = cartItems)

        val response = cartApi.updateCart(cartId, request, "Bearer $token")
        Log.d(TAG, "updateCart: Response code=${response.code()}")

        if (response.isSuccessful) {
            val cart = response.body() ?: Cart()
            Log.d(TAG, "updateCart: ✅ Success")
            Result.success(cart)
        } else {
            Log.e(TAG, "updateCart: ❌ Error ${response.code()}")
            Result.failure(Exception("Error: ${response.code()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "updateCart: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }

    /**
     * Update quantity của 1 cart item (PUT /carts/item/{id})
     * Gửi PUT request và auto-fetch full cart để sync
     */
    suspend fun updateCartItemQuantity(
        cartItemId: Int,
        quantity: Int,
        customerId: Int,
        token: String
    ): Result<Cart> = try {
        Log.d(TAG, "updateCartItemQuantity: Updating item $cartItemId to quantity $quantity")
        val request = UpdateCartRequest(
            cart_item_id = cartItemId,
            quantity = quantity
        )

        // Step 1: PUT /carts/item/{id} - Update quantity
        val response = cartApi.updateCartItem(cartItemId, request, "Bearer $token")
        Log.d(TAG, "updateCartItemQuantity: PUT Response code=${response.code()}")

        if (response.isSuccessful) {
            Log.d(TAG, "updateCartItemQuantity: ✅ PUT Success - Item updated to quantity $quantity")

            // Step 2: GET /carts/{customerId} - Fetch updated cart
            Log.d(TAG, "updateCartItemQuantity: Fetching updated cart from server")
            val getResponse = cartApi.getCart(customerId, "Bearer $token")
            if (getResponse.isSuccessful) {
                val cart = getResponse.body() ?: Cart()
                Log.d(TAG, "updateCartItemQuantity: ✅ GET Success - Cart has ${cart.cart_items.size} items")
                Result.success(cart)
            } else {
                Log.w(TAG, "updateCartItemQuantity: GET failed after PUT success")
                // Return empty cart as fallback
                Result.success(Cart(customer_id = customerId))
            }
        } else {
            Log.e(TAG, "updateCartItemQuantity: ❌ Error ${response.code()}")
            Result.failure(Exception("Error: ${response.code()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "updateCartItemQuantity: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }

    /**
     * Xóa 1 item từ cart (DELETE /carts/item/{id})
     * Sau đó auto-fetch full cart để sync
     */
    suspend fun deleteCartItem(
        cartItemId: Int,
        customerId: Int,
        token: String
    ): Result<Cart> = try {
        Log.d(TAG, "deleteCartItem: Deleting cart item $cartItemId")
        val response = cartApi.deleteCartItem(cartItemId, "Bearer $token")
        Log.d(TAG, "deleteCartItem: DELETE Response code=${response.code()}")

        if (response.isSuccessful) {
            Log.d(TAG, "deleteCartItem: ✅ DELETE Success")

            // Step 2: GET /carts/{customerId} - Fetch updated cart
            Log.d(TAG, "deleteCartItem: Fetching updated cart from server")
            val getResponse = cartApi.getCart(customerId, "Bearer $token")
            if (getResponse.isSuccessful) {
                val cart = getResponse.body() ?: Cart()
                Log.d(TAG, "deleteCartItem: ✅ GET Success - Cart has ${cart.cart_items.size} items")
                Result.success(cart)
            } else {
                Log.w(TAG, "deleteCartItem: GET failed after DELETE success")
                // Return empty cart as fallback
                Result.success(Cart(customer_id = customerId))
            }
        } else {
            Log.e(TAG, "deleteCartItem: ❌ Error ${response.code()}")
            Result.failure(Exception("Error: ${response.code()}"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "deleteCartItem: ❌ Exception - ${e.message}", e)
        Result.failure(e)
    }
}

package com.example.btl.Fragments.Shopping

import android.os.Bundle
import android.os.Handler
import android.os.Looper
import android.util.Log
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.fragment.app.Fragment
import androidx.lifecycle.lifecycleScope
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.viewpager2.widget.CompositePageTransformer
import androidx.viewpager2.widget.MarginPageTransformer
import androidx.viewpager2.widget.ViewPager2
import com.example.btl.Adapters.BestDealAdapter
import com.example.btl.Adapters.BannerAdapter
import com.example.btl.DataStore.TokenManager
import com.example.btl.R
import com.example.btl.Repository.ProductRepository
import com.example.btl.Utils.NetworkUtils
import com.example.btl.databinding.FragmentHomeBinding
import com.google.android.material.tabs.TabLayoutMediator
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.launch
import kotlinx.coroutines.withTimeoutOrNull

class HomeFragment : Fragment() {
    private lateinit var binding: FragmentHomeBinding
    private lateinit var tokenManager: TokenManager
    private var bestDealAdapter: BestDealAdapter? = null
    private var bannerAdapter: BannerAdapter? = null
    private var bannerHandler: Handler? = null

    companion object {
        private const val TAG = "HomeFragment"
        private const val BANNER_AUTO_SCROLL_DELAY = 3000L // 3 seconds
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        binding = FragmentHomeBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        Log.d(TAG, "✅ onViewCreated called")

        try {
            tokenManager = TokenManager(requireContext())
            Log.d(TAG, "✅ TokenManager initialized")

            // Setup lightweight UI elements on main thread
            setupBestDealsRecyclerView()
            setupSearchBox()

            Log.d(TAG, "✅ RecyclerViews and search box setup complete")

            // FIX: Move banner setup to background thread to prevent ANR
            // Banner carousel setup can be slightly heavy, so we defer it
            viewLifecycleOwner.lifecycleScope.launch {
                try {
                    setupBannerCarouselAsync()
                    Log.d(TAG, "✅ Banner carousel setup completed asynchronously")
                } catch (e: Exception) {
                    Log.e(TAG, "❌ Error setting up banner carousel: ${e.message}", e)
                }
            }

            // FIX #1: Replace hardcoded delay with Flow-based token waiting
            // This properly waits for token availability without blocking
            initializeDataLoading()

        } catch (e: Exception) {
            Log.e(TAG, "❌ Error in onViewCreated: ${e.message}", e)
            e.printStackTrace()
            Toast.makeText(requireContext(), "Error: ${e.message}", Toast.LENGTH_SHORT).show()
        }
    }

    /**
     * FIX #1: Initialize data loading using reactive Flow with validation
     * Properly waits for token and validates it before loading data
     */
    private fun initializeDataLoading() {
        Log.d(TAG, "⏳ Waiting for token using Flow (non-blocking)...")
        viewLifecycleOwner.lifecycleScope.launch {
            try {
                // Wait for token to be available (non-blocking) - with timeout protection
                val token = withTimeoutOrNull(5000) {  // 5 second timeout
                    tokenManager.getTokenFlow().first()
                }

                Log.d(TAG, " Token from Flow: ${if (token != null) token.take(20) + "..." else "NULL"}")

                // Validate token: must not be null, empty, or just whitespace
                if (!token.isNullOrEmpty() && token.trim().isNotEmpty()) {
                    Log.d(TAG, "✅ Valid token received: ${token.trim().take(20)}...")
                    loadBestDeals(token.trim())
                } else {
                    Log.e(TAG, "❌ Invalid token - null or empty")
                    if (isAdded) {
                        Toast.makeText(
                            requireContext(),
                            "Authentication failed. Please login again.",
                            Toast.LENGTH_SHORT
                        ).show()
                    }
                }
            } catch (e: Exception) {
                when {
                    e.message?.contains("timeout", ignoreCase = true) == true -> {
                        Log.e(TAG, "❌ Token loading timeout after 5 seconds")
                        if (isAdded) {
                            Toast.makeText(
                                requireContext(),
                                "Token loading timeout. Please try again.",
                                Toast.LENGTH_SHORT
                            ).show()
                        }
                    }
                    else -> {
                        Log.e(TAG, "❌ Error waiting for token: ${e.message}", e)
                        e.printStackTrace()
                        if (isAdded) {
                            Toast.makeText(
                                requireContext(),
                                "Error loading data: ${e.message}",
                                Toast.LENGTH_SHORT
                            ).show()
                        }
                    }
                }
            }
        }
    }

    private fun setupSearchBox() {
        Log.d(TAG, "Setting up search box")
        binding.tvSearch.setOnClickListener {
            Toast.makeText(requireContext(), "Search coming soon", Toast.LENGTH_SHORT).show()
            Log.d(TAG, "Search box clicked")
        }
    }

    /**
     * Setup banner carousel with auto-scroll
     * Optimized for memory efficiency
     */
    private fun setupBannerCarousel() {
        try {
            Log.d(TAG, "Setting up Banner Carousel")

            // Tạo danh sách banner
            val bannerList = listOf(
                R.drawable.banner_test1,
                R.drawable.banner_test2
            )

            // Tạo adapter - LAZY CREATE to avoid memory issues
            bannerAdapter = BannerAdapter(bannerList)
            binding.vpBanner.adapter = bannerAdapter
            binding.vpBanner.offscreenPageLimit = 1  // FIX: Reduce memory consumption by only keeping 1 page

            // Setup transformer (zoom hiệu ứng) - SIMPLIFIED to reduce memory pressure
            val compositePageTransformer = CompositePageTransformer().apply {
                addTransformer(MarginPageTransformer(8))
            }
            binding.vpBanner.setPageTransformer(compositePageTransformer)

            // Connect TabLayout with ViewPager2 (dots indicator)
            // Use try-catch to handle potential OOM during TabLayoutMediator initialization
            try {
                TabLayoutMediator(binding.tlDots, binding.vpBanner) { _, _ -> }.attach()
            } catch (e: OutOfMemoryError) {
                Log.e(TAG, "❌ OOM Error during TabLayout setup: ${e.message}")
                // Continue without tab indicator if memory is critical
            }

            // Auto-scroll banner
            startBannerAutoScroll()

            // Listen khi user scroll thì reset timer
            binding.vpBanner.registerOnPageChangeCallback(object : ViewPager2.OnPageChangeCallback() {
                override fun onPageSelected(position: Int) {
                    super.onPageSelected(position)
                    resetBannerAutoScroll()
                }
            })

            Log.d(TAG, "✅ Banner Carousel initialized with ${bannerList.size} images")
        } catch (e: Exception) {
            Log.e(TAG, "❌ Error setting up banner: ${e.message}", e)
            // Don't crash if banner setup fails
        }
    }

    /**
     * Bắt đầu auto-scroll banner
     */
    private fun startBannerAutoScroll() {
        if (bannerHandler == null) {
            bannerHandler = Handler(Looper.getMainLooper())
        }

        bannerHandler?.postDelayed(object : Runnable {
            override fun run() {
                // Kiểm tra xem fragment còn tồn tại không
                if (isAdded && ::binding.isInitialized) {
                    val nextItem = (binding.vpBanner.currentItem + 1) % Int.MAX_VALUE
                    binding.vpBanner.setCurrentItem(nextItem, true)
                    bannerHandler?.postDelayed(this, BANNER_AUTO_SCROLL_DELAY)
                }
            }
        }, BANNER_AUTO_SCROLL_DELAY)
    }

    /**
     * Reset auto-scroll timer khi user tương tác
     */
    private fun resetBannerAutoScroll() {
        bannerHandler?.removeCallbacksAndMessages(null)
        startBannerAutoScroll()
    }

    /**
     * Stop auto-scroll khi fragment bị destroy
     */
    private fun stopBannerAutoScroll() {
        bannerHandler?.removeCallbacksAndMessages(null)
    }


    private fun setupBestDealsRecyclerView() {
        Log.d(TAG, "Setting up Best Deals RecyclerView")
        binding.rvBestDeals.layoutManager = LinearLayoutManager(
            requireContext(),
            LinearLayoutManager.HORIZONTAL,
            false
        )
        bestDealAdapter = BestDealAdapter(emptyList())
        binding.rvBestDeals.adapter = bestDealAdapter
        Log.d(TAG, "✅ Best Deals RecyclerView initialized")
    }

    /**
     * Load best deals from API
     * FIX #3: Added network connectivity check
     *
     * @param token JWT token for authentication
     */
    private fun loadBestDeals(token: String) {
        Log.d(TAG, " loadBestDeals started")
        Log.d(TAG, " Fragment attached: $isAdded")

        // Check if fragment is still attached
        if (!isAdded) {
            Log.w(TAG, "Fragment is not attached, skipping data load")
            return
        }

        viewLifecycleOwner.lifecycleScope.launch {
            try {
                // FIX #3: Check network connectivity before making API call
                val isNetworkAvailable = NetworkUtils.isNetworkAvailable(requireContext())
                val networkType = NetworkUtils.getNetworkTypeName(requireContext())

                Log.d(TAG, " Network Check: Available=$isNetworkAvailable, Type=$networkType")

                if (!isNetworkAvailable) {
                    Log.e(TAG, "❌ No internet connection")
                    if (isAdded) {
                        Toast.makeText(
                            requireContext(),
                            "No internet connection. Please check your network.",
                            Toast.LENGTH_LONG
                        ).show()
                    }
                    return@launch
                }

                Log.d(TAG, "✅ Network available, fetching products...")
                Log.d(TAG, " Calling ProductRepository.getAllProducts()...")
                val repository = ProductRepository()
                val result = repository.getAllProducts(token)

                result.onSuccess { products ->
                    // Check if fragment is still attached before updating UI
                    if (!isAdded) {
                        Log.w(TAG, "Fragment detached, skipping UI update")
                        return@onSuccess
                    }

                    Log.d(TAG, "✅ SUCCESS: Retrieved ${products.size} products")

                    // Display products info
                    products.forEachIndexed { index, product ->
                        Log.d(TAG, "  [$index] ${product.product_id}: ${product.name} - Image: ${product.getPrimaryImageUrl().take(50)}...")
                    }

                    if (products.isEmpty()) {
                        Log.w(TAG, "⚠️ WARNING: No products received from API")
                        Toast.makeText(requireContext(), "No products available", Toast.LENGTH_SHORT).show()
                        return@onSuccess
                    }

                    // Take top 4 products as best deals
                    val bestDeals = products.take(4)
                    Log.d(TAG, " Best Deals: ${bestDeals.size} products")
                    bestDeals.forEachIndexed { index, product ->
                        Log.d(TAG, "  BestDeal[$index]: ${product.name}")
                    }
                    bestDealAdapter?.updateProducts(bestDeals)
                    Log.d(TAG, "✅ Best Deals adapter updated")


                    Toast.makeText(
                        requireContext(),
                        "Loaded ${products.size} products",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                result.onFailure { exception ->
                    Log.e(TAG, "❌ FAILURE: ${exception.message}", exception)
                    exception.printStackTrace()
                    if (isAdded) {
                        Toast.makeText(
                            requireContext(),
                            "Failed to load products: ${exception.message}",
                            Toast.LENGTH_LONG
                        ).show()
                    }
                }

            } catch (e: Exception) {
                Log.e(TAG, "❌ EXCEPTION: ${e.message}", e)
                e.printStackTrace()
                if (isAdded) {
                    Toast.makeText(
                        requireContext(),
                        "Error: ${e.message}",
                        Toast.LENGTH_LONG
                    ).show()
                }
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        stopBannerAutoScroll()
    }
}

