                    Log.d(TAG, " Best Deals: ${bestDeals.size} products")
                    bestDeals.forEachIndexed { index, product ->
                        Log.d(TAG, "  BestDeal[$index]: ${product.name}")
                    }
                    bestDealAdapter?.updateProducts(bestDeals)
                    Log.d(TAG, "✅ Best Deals adapter updated")


                    Toast.makeText(
                        requireContext(),
                        "Loaded ${products.size} products",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                result.onFailure { exception ->
                    Log.e(TAG, "❌ FAILURE: ${exception.message}", exception)
                    exception.printStackTrace()
                    if (isAdded) {
                        Toast.makeText(
                            requireContext(),
                            "Failed to load products: ${exception.message}",
                            Toast.LENGTH_LONG
                        ).show()
                    }
                }

            } catch (e: Exception) {
                Log.e(TAG, "❌ EXCEPTION: ${e.message}", e)
                e.printStackTrace()
                if (isAdded) {
                    Toast.makeText(
                        requireContext(),
                        "Error: ${e.message}",
                        Toast.LENGTH_LONG
                    ).show()
                }
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        stopBannerAutoScroll()
    }
}

package com.example.btl.Fragments.Shopping

import android.os.Bundle
import android.util.Log
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.fragment.app.Fragment
import androidx.lifecycle.lifecycleScope
import androidx.navigation.fragment.findNavController
import androidx.recyclerview.widget.LinearLayoutManager
import com.example.btl.Adapters.OrdersListAdapter
import com.example.btl.Api.RetrofitClient
import com.example.btl.DataStore.TokenManager
import com.example.btl.Model.Order
import com.example.btl.Model.UpdateOrderRequest
import com.example.btl.R
import com.example.btl.databinding.FragmentOrdersListBinding
import kotlinx.coroutines.launch

class OrdersListFragment : Fragment() {
    private lateinit var binding: FragmentOrdersListBinding
    private lateinit var ordersAdapter: OrdersListAdapter
    private val TAG = "OrdersListFragment"
    private val orders = mutableListOf<Order>()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        binding = FragmentOrdersListBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        Log.d(TAG, "onViewCreated: Initializing OrdersListFragment")

        setupRecyclerView()
        setupClickListeners()
        loadOrders()
    }

    private fun setupRecyclerView() {
        ordersAdapter = OrdersListAdapter(
            orders,
            onOrderClick = { order ->
                // Handle order item click - navigate to order detail
                Log.d(TAG, "Order clicked: ${order.order_id}")
                val bundle = Bundle().apply {
                    putInt("order_id", order.order_id ?: 0)
                }
                findNavController().navigate(R.id.action_ordersListFragment_to_orderDetailFragment, bundle)
            },
            onCancelOrderClick = { order ->
                // Handle cancel order click
                Log.d(TAG, "Cancel order clicked: ${order.order_id}")
                showCancelConfirmation(order)
            }
        )

        binding.rvOrders.apply {
            layoutManager = LinearLayoutManager(requireContext())
            adapter = ordersAdapter
        }
    }

    private fun showCancelConfirmation(order: Order) {
        androidx.appcompat.app.AlertDialog.Builder(requireContext())
            .setTitle("Hủy đơn hàng")
            .setMessage("Bạn có chắc chắn muốn hủy đơn hàng #${order.order_id}?")
            .setPositiveButton("Hủy") { _, _ ->
                cancelOrder(order)
            }
            .setNegativeButton("Không") { dialog, _ ->
                dialog.dismiss()
            }
            .show()
    }

    private fun cancelOrder(order: Order) {
        viewLifecycleOwner.lifecycleScope.launch {
            try {
                binding.progressBar.visibility = View.VISIBLE
                val tokenManager = TokenManager(requireContext())
                val token = tokenManager.getToken() ?: ""

                // Call update order API to change status to CANCELLED
                val requestBody = mapOf("order_status" to "cancelled")
                val response = RetrofitClient.orderApi.updateOrder(
                    orderId = order.order_id ?: 0,
                    request = requestBody,
                    token = "Bearer $token"
                )

                if (response.isSuccessful) {
                    Toast.makeText(requireContext(), "Đơn hàng đã hủy thành công", Toast.LENGTH_SHORT).show()
                    // Reload orders
                    loadOrders()
                } else {
                    Toast.makeText(requireContext(), "Lỗi: Không thể hủy đơn hàng", Toast.LENGTH_SHORT).show()
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error canceling order: ${e.message}", e)
                Toast.makeText(requireContext(), "Lỗi: ${e.message}", Toast.LENGTH_SHORT).show()
            } finally {
                binding.progressBar.visibility = View.GONE
            }
        }
    }

    private fun setupClickListeners() {
        binding.imageCloseOrders.setOnClickListener {
            findNavController().popBackStack()
        }
    }

    private fun loadOrders() {
        Log.d(TAG, "loadOrders: Loading orders from API")
        viewLifecycleOwner.lifecycleScope.launch {
            try {
                binding.progressBar.visibility = View.VISIBLE
                binding.tvEmptyOrders.visibility = View.GONE

                val tokenManager = TokenManager(requireContext())
                val token = tokenManager.getToken() ?: ""
                val response = RetrofitClient.orderApi.getOrders("Bearer $token")

                if (response.isSuccessful && response.body() != null) {
                    val fetchedOrders = response.body()!!
                    Log.d(TAG, "Orders loaded: ${fetchedOrders.size}")

                    orders.clear()
                    orders.addAll(fetchedOrders)
                    ordersAdapter.notifyDataSetChanged()

                    if (orders.isEmpty()) {
                        binding.tvEmptyOrders.visibility = View.VISIBLE
                        Log.d(TAG, "No orders found")
                    } else {
                        binding.tvEmptyOrders.visibility = View.GONE
                    }
                } else {
                    Log.e(TAG, "Failed to load orders: ${response.code()}")
                    binding.tvEmptyOrders.visibility = View.VISIBLE
                    binding.tvEmptyOrders.text = "Failed to load orders: ${response.code()}"
                    Toast.makeText(requireContext(), "Failed to load orders", Toast.LENGTH_SHORT).show()
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error loading orders: ${e.message}", e)
                binding.tvEmptyOrders.visibility = View.VISIBLE
                binding.tvEmptyOrders.text = "Error: ${e.message}"
                Toast.makeText(requireContext(), "Error: ${e.message}", Toast.LENGTH_SHORT).show()
            } finally {
                binding.progressBar.visibility = View.GONE
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        Log.d(TAG, "onDestroyView: Cleaning up OrdersListFragment")
    }
}

