package com.example.btl.Fragments.Shopping

import android.os.Bundle
import android.os.Handler
import android.os.Looper
import android.text.Editable
import android.text.TextWatcher
import android.util.Log
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.fragment.app.Fragment
import androidx.lifecycle.ViewModelProvider
import androidx.navigation.fragment.findNavController
import androidx.recyclerview.widget.LinearLayoutManager
import com.example.btl.Adapters.PopularSearchAdapter
import com.example.btl.DataStore.TokenManager
import com.example.btl.ViewModel.SearchViewModel
import com.example.btl.databinding.FragmentSearchBinding

class SearchFragment : Fragment() {
    private lateinit var binding: FragmentSearchBinding
    private lateinit var viewModel: SearchViewModel
    private lateinit var tokenManager: TokenManager
    private lateinit var adapter: PopularSearchAdapter
    private val TAG = "SearchFragment"

    // Debounce search queries (prevent too many API calls)
    private val searchHandler = Handler(Looper.getMainLooper())
    private var searchRunnable: Runnable? = null
    private val SEARCH_DELAY_MS = 300L  // Wait 300ms after user stops typing

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        binding = FragmentSearchBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onDestroyView() {
        super.onDestroyView()
        // Cancel pending search operations to avoid memory leaks
        searchRunnable?.let { searchHandler.removeCallbacks(it) }
    }


    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        Log.d(TAG, "onViewCreated called")

        tokenManager = TokenManager(requireContext())

        // Initialize ViewModel - use activity scope so filters persist across fragments
        viewModel = ViewModelProvider(requireActivity()).get(SearchViewModel::class.java)
        viewModel.init(requireContext())

        // Setup UI
        setupUI()

        // Setup observers
        setupObservers()

        // Load popular products
        getTokenAndLoadPopular()
    }

    private fun setupUI() {
        Log.d(TAG, "setupUI called")

        // Setup RecyclerView for popular search
        adapter = PopularSearchAdapter(emptyList())
        binding.rvPopularSearch.apply {
            layoutManager = LinearLayoutManager(requireContext())
            adapter = this@SearchFragment.adapter
        }

        // Setup search input with debouncing to prevent spam
        binding.etSearch.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}

            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                val query = s?.toString()?.trim() ?: ""
                Log.d(TAG, "Search query: '$query'")

                // Remove pending search requests
                searchRunnable?.let { searchHandler.removeCallbacks(it) }

                if (query.isNotEmpty()) {
                    // Schedule search after delay
                    searchRunnable = Runnable {
                        getTokenAndSearch(query)
                    }
                    searchHandler.postDelayed(searchRunnable!!, SEARCH_DELAY_MS)
                }
            }

            override fun afterTextChanged(s: Editable?) {}
        })

        // Back button click
        binding.ivBack.setOnClickListener {
            Log.d(TAG, "Back button clicked")
            findNavController().navigateUp()
        }

        // Filter button click
        binding.ivFilter.setOnClickListener {
            Log.d(TAG, "Filter button clicked")
            val filterBottomSheet = FilterBottomSheetFragment()
            filterBottomSheet.show(childFragmentManager, FilterBottomSheetFragment::class.java.simpleName)
        }

        // Clear all button click
        binding.tvClearAll.setOnClickListener {
            Log.d(TAG, "Clear All clicked")
            viewModel.clearLastSearches()
            updateLastSearchChips(emptyList())
        }

        // Setup chip click listeners
        setupChipListeners()
    }

    private fun setupChipListeners() {
        Log.d(TAG, "setupChipListeners called")

        val chips = listOf(
            binding.chipElectronics to "Electronics",
            binding.chipPants to "Pants",
            binding.chipThreeSecond to "Three Second",
            binding.chipLongShirt to "Long shirt"
        )

        chips.forEach { (chip, query) ->
            chip.setOnClickListener {
                Log.d(TAG, "Chip clicked: $query")
                binding.etSearch.setText(query)
            }
        }
    }

    private fun setupObservers() {
        Log.d(TAG, "setupObservers called")

        viewModel.searchResults.observe(viewLifecycleOwner) { products ->
            Log.d(TAG, "searchResults updated: ${products.size} products")
            adapter.updateProducts(products)

            // Only show toast for actual errors, not for empty results
            if (products.isEmpty() && binding.etSearch.text.toString().isNotEmpty()) {
                Log.d(TAG, "No products found for query")
                // Use logging instead of toast to avoid spam
            }
        }

        viewModel.isLoading.observe(viewLifecycleOwner) { isLoading ->
            Log.d(TAG, "isLoading: $isLoading")
            binding.apply {
                if (isLoading) {
                    // Could show progress bar here
                } else {
                    // Hide progress bar
                }
            }
        }

        viewModel.errorMessage.observe(viewLifecycleOwner) { error ->
            if (error != null) {
                Log.e(TAG, "Error: $error")
                // Only show critical errors to avoid toast spam
                if (error.contains("401") || error.contains("500")) {
                    Toast.makeText(requireContext(), error, Toast.LENGTH_SHORT).show()
                }
            }
        }

        viewModel.lastSearchQueries.observe(viewLifecycleOwner) { queries ->
            Log.d(TAG, "lastSearchQueries updated: ${queries.size} queries")
            updateLastSearchChips(queries)
        }

        viewModel.popularProducts.observe(viewLifecycleOwner) { products ->
            Log.d(TAG, "popularProducts updated: ${products.size} products")
            adapter.updateProducts(products)
        }
    }

    private fun updateLastSearchChips(queries: List<String>) {
        Log.d(TAG, "updateLastSearchChips: ${queries.size} queries")

        // Hide chips if no queries
        if (queries.isEmpty()) {
            binding.llChipsRow1.visibility = View.GONE
            binding.llChipsRow2.visibility = View.GONE
            return
        }

        binding.llChipsRow1.visibility = View.VISIBLE

        // Update first row
        if (queries.isNotEmpty()) {
            binding.chipElectronics.apply {
                text = queries.getOrNull(0)?.let { "$it ×" } ?: ""
                visibility = if (queries.isNotEmpty()) View.VISIBLE else View.GONE
                setOnClickListener {
                    if (queries.isNotEmpty()) {
                        viewModel.removeLastSearch(queries[0])
                    }
                }
            }
        }

        if (queries.size > 1) {
            binding.chipPants.apply {
                text = "${queries[1]} ×"
                visibility = View.VISIBLE
                setOnClickListener {
                    viewModel.removeLastSearch(queries[1])
                }
            }
        } else {
            binding.chipPants.visibility = View.GONE
        }

        // Update second row
        if (queries.size > 2 || queries.size > 3) {
            binding.llChipsRow2.visibility = View.VISIBLE

            if (queries.size > 2) {
                binding.chipThreeSecond.apply {
                    text = "${queries[2]} ×"
                    visibility = View.VISIBLE
                    setOnClickListener {
                        viewModel.removeLastSearch(queries[2])
                    }
                }
            }

            if (queries.size > 3) {
                binding.chipLongShirt.apply {
                    text = "${queries[3]} ×"
                    visibility = View.VISIBLE
                    setOnClickListener {
                        viewModel.removeLastSearch(queries[3])
                    }
                }
            }
        } else {
            binding.llChipsRow2.visibility = View.GONE
        }
    }

    private fun getTokenAndSearch(query: String) {
        Log.d(TAG, "getTokenAndSearch: $query")

        val token = tokenManager.getToken()
        if (token != null) {
            Log.d(TAG, "Token retrieved, searching...")
            viewModel.searchProducts(query, token)
        } else {
            Log.e(TAG, "No token available")
            Toast.makeText(requireContext(), "Please login first", Toast.LENGTH_SHORT).show()
        }
    }

    private fun getTokenAndLoadPopular() {
        Log.d(TAG, "getTokenAndLoadPopular called")

        val token = tokenManager.getToken()
        if (token != null) {
            Log.d(TAG, "Token retrieved, loading popular products...")
            viewModel.loadPopularProducts(token)
        } else {
            Log.e(TAG, "No token available")
            Toast.makeText(requireContext(), "Please login first", Toast.LENGTH_SHORT).show()
        }
    }
}

package com.example.btl.Fragments.Shopping

import android.os.Bundle
import android.os.Handler
import android.os.Looper
import android.text.Editable
import android.text.TextWatcher
import android.util.Log
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.fragment.app.Fragment
import androidx.lifecycle.ViewModelProvider
import androidx.navigation.fragment.findNavController
import androidx.recyclerview.widget.LinearLayoutManager
import com.example.btl.Adapters.PopularSearchAdapter
import com.example.btl.DataStore.TokenManager
import com.example.btl.ViewModel.SearchViewModel
import com.example.btl.databinding.FragmentSearchBinding

class SearchFragment : Fragment() {
    private lateinit var binding: FragmentSearchBinding
    private lateinit var viewModel: SearchViewModel
    private lateinit var tokenManager: TokenManager
    private lateinit var adapter: PopularSearchAdapter
    private val TAG = "SearchFragment"
    
    // Debounce search queries (prevent too many API calls)
    private val searchHandler = Handler(Looper.getMainLooper())
    private var searchRunnable: Runnable? = null
    private val SEARCH_DELAY_MS = 300L  // Wait 300ms after user stops typing

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        binding = FragmentSearchBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onDestroyView() {
        super.onDestroyView()
        // Cancel pending search operations to avoid memory leaks
        searchRunnable?.let { searchHandler.removeCallbacks(it) }
    }


    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        Log.d(TAG, "onViewCreated called")

        tokenManager = TokenManager(requireContext())
        
        // Initialize ViewModel - use activity scope so filters persist across fragments
        viewModel = ViewModelProvider(requireActivity()).get(SearchViewModel::class.java)
        viewModel.init(requireContext())

        // Setup UI
        setupUI()

        // Setup observers
        setupObservers()

        // Load popular products
        getTokenAndLoadPopular()
    }

    private fun setupUI() {
        Log.d(TAG, "setupUI called")

        // Setup RecyclerView for popular search
        adapter = PopularSearchAdapter(emptyList())
        binding.rvPopularSearch.apply {
            layoutManager = LinearLayoutManager(requireContext())
            adapter = this@SearchFragment.adapter
        }

        // Setup search input with debouncing to prevent spam
        binding.etSearch.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}

            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                val query = s?.toString()?.trim() ?: ""
                Log.d(TAG, "Search query: '$query'")

                // Remove pending search requests
                searchRunnable?.let { searchHandler.removeCallbacks(it) }

                if (query.isNotEmpty()) {
                    // Schedule search after delay
                    searchRunnable = Runnable {
                        getTokenAndSearch(query)
                    }
                    searchHandler.postDelayed(searchRunnable!!, SEARCH_DELAY_MS)
                } else {
                    viewModel.clearSearchResults()
                    getTokenAndLoadPopular()
                }
            }

            override fun afterTextChanged(s: Editable?) {}
        })

        // Back button click
        binding.ivBack.setOnClickListener {
            Log.d(TAG, "Back button clicked")
            findNavController().navigateUp()
        }

        // Filter button click
        binding.ivFilter.setOnClickListener {
            Log.d(TAG, "Filter button clicked")
            val filterBottomSheet = FilterBottomSheetFragment()
            filterBottomSheet.show(childFragmentManager, FilterBottomSheetFragment::class.java.simpleName)
        }

        // Clear all button click
        binding.tvClearAll.setOnClickListener {
            Log.d(TAG, "Clear All clicked")
            viewModel.clearLastSearches()
            updateLastSearchChips(emptyList())
        }

        // Setup chip click listeners
        setupChipListeners()
    }

    private fun setupChipListeners() {
        Log.d(TAG, "setupChipListeners called")

        val chips = listOf(
            binding.chipElectronics to "Electronics",
            binding.chipPants to "Pants",
            binding.chipThreeSecond to "Three Second",
            binding.chipLongShirt to "Long shirt"
        )

        chips.forEach { (chip, query) ->
            chip.setOnClickListener {
                Log.d(TAG, "Chip clicked: $query")
                binding.etSearch.setText(query)
            }
        }
    }

    private fun setupObservers() {
        Log.d(TAG, "setupObservers called")

        viewModel.searchResults.observe(viewLifecycleOwner) { products ->
            Log.d(TAG, "searchResults updated: ${products.size} products")
            adapter.updateProducts(products)

            if (products.isEmpty() && binding.etSearch.text.toString().isNotEmpty()) {
                Log.d(TAG, "No products found for query")
            }
        }

        viewModel.isLoading.observe(viewLifecycleOwner) { isLoading ->
            Log.d(TAG, "isLoading: $isLoading")
            binding.apply {
                if (isLoading) {
                    // Could show progress bar here
                } else {
                    // Hide progress bar
                }
            }
        }

        viewModel.errorMessage.observe(viewLifecycleOwner) { error ->
            if (error != null) {
                Log.e(TAG, "Error: $error")
                // Only show critical errors to avoid toast spam
                if (error.contains("401") || error.contains("500")) {
                    Toast.makeText(requireContext(), error, Toast.LENGTH_SHORT).show()
                }
            }
        }

        viewModel.lastSearchQueries.observe(viewLifecycleOwner) { queries ->
            Log.d(TAG, "lastSearchQueries updated: ${queries.size} queries")
            updateLastSearchChips(queries)
        }

        viewModel.popularProducts.observe(viewLifecycleOwner) { products ->
            Log.d(TAG, "popularProducts updated: ${products.size} products")
            val query = binding.etSearch.text?.toString()?.trim().orEmpty()
            if (query.isEmpty()) {
                adapter.updateProducts(products)
            }
        }
    }

    private fun updateLastSearchChips(queries: List<String>) {
        Log.d(TAG, "updateLastSearchChips: ${queries.size} queries")

        // Hide chips if no queries
        if (queries.isEmpty()) {
            binding.llChipsRow1.visibility = View.GONE
            binding.llChipsRow2.visibility = View.GONE
            return
        }

        binding.llChipsRow1.visibility = View.VISIBLE
        
        // Update first row
        if (queries.isNotEmpty()) {
            binding.chipElectronics.apply {
                text = queries.getOrNull(0)?.let { "$it ×" } ?: ""
                visibility = if (queries.isNotEmpty()) View.VISIBLE else View.GONE
                setOnClickListener {
                    if (queries.isNotEmpty()) {
                        viewModel.removeLastSearch(queries[0])
                    }
                }
            }
        }

        if (queries.size > 1) {
            binding.chipPants.apply {
                text = "${queries[1]} ×"
                visibility = View.VISIBLE
                setOnClickListener {
                    viewModel.removeLastSearch(queries[1])
                }
            }
        } else {
            binding.chipPants.visibility = View.GONE
        }

        // Update second row
        if (queries.size > 2 || queries.size > 3) {
            binding.llChipsRow2.visibility = View.VISIBLE

            if (queries.size > 2) {
                binding.chipThreeSecond.apply {
                    text = "${queries[2]} ×"
                    visibility = View.VISIBLE
                    setOnClickListener {
                        viewModel.removeLastSearch(queries[2])
                    }
                }
            }

            if (queries.size > 3) {
                binding.chipLongShirt.apply {
                    text = "${queries[3]} ×"
                    visibility = View.VISIBLE
                    setOnClickListener {
                        viewModel.removeLastSearch(queries[3])
                    }
                }
            }
        } else {
            binding.llChipsRow2.visibility = View.GONE
        }
    }

    private fun getTokenAndSearch(query: String) {
        Log.d(TAG, "getTokenAndSearch: $query")
        
        val token = tokenManager.getToken()
        if (token != null) {
            Log.d(TAG, "Token retrieved, searching...")
            viewModel.searchProducts(query, token)
        } else {
            Log.e(TAG, "No token available")
            Toast.makeText(requireContext(), "Please login first", Toast.LENGTH_SHORT).show()
        }
    }

    private fun getTokenAndLoadPopular() {
        Log.d(TAG, "getTokenAndLoadPopular called")
        
        val token = tokenManager.getToken()
        if (token != null) {
            Log.d(TAG, "Token retrieved, loading popular products...")
            viewModel.loadPopularProducts(token)
        } else {
            Log.e(TAG, "No token available")
            Toast.makeText(requireContext(), "Please login first", Toast.LENGTH_SHORT).show()
        }
    }
}

package com.example.btl.ViewModel

import android.app.Application
import android.util.Log
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.viewModelScope
import com.example.btl.DataStore.DataStoreManager
import com.example.btl.Model.Product
import com.example.btl.Repository.ProductRepository
import kotlinx.coroutines.launch

class SearchViewModel(application: Application) : AndroidViewModel(application) {
    private var productRepository: ProductRepository? = null
    private val TAG = "SearchViewModel"

    private val _originalSearchResults = MutableLiveData<List<Product>>(emptyList())

    private val _searchResults = MutableLiveData<List<Product>>(emptyList())
    val searchResults: LiveData<List<Product>> = _searchResults

    private val _isLoading = MutableLiveData<Boolean>(false)
    val isLoading: LiveData<Boolean> = _isLoading

    private val _errorMessage = MutableLiveData<String?>(null)
    val errorMessage: LiveData<String?> = _errorMessage

    private val _lastSearchQueries = MutableLiveData<List<String>>(emptyList())
    val lastSearchQueries: LiveData<List<String>> = _lastSearchQueries

    private val _popularProducts = MutableLiveData<List<Product>>(emptyList())
    val popularProducts: LiveData<List<Product>> = _popularProducts

    private val _selectedCategoryId = MutableLiveData<Int?>(null)
    val selectedCategoryId: LiveData<Int?> = _selectedCategoryId

    private val _priceRange = MutableLiveData<Pair<Int, Int>?>(null)
    val priceRange: LiveData<Pair<Int, Int>?> = _priceRange

    private val _selectedColors = MutableLiveData<List<String>>(emptyList())
    val selectedColors: LiveData<List<String>> = _selectedColors

    private val _selectedLocations = MutableLiveData<List<String>>(emptyList())
    val selectedLocations: LiveData<List<String>> = _selectedLocations

    fun init() {
        if (productRepository == null) {
            productRepository = ProductRepository()
        }

        viewModelScope.launch {
            val history = DataStoreManager.getSearchHistory(getApplication())
            _lastSearchQueries.value = history
        }
    }

    /**
     * Xóa kết quả tìm kiếm hiện tại
     */
    fun clearSearchResults() {
        _originalSearchResults.value = emptyList()
        _searchResults.value = emptyList()
    }

    /**
     * Lọc theo địa điểm
     */
    fun setFilterLocations(locations: List<String>) {
        _selectedLocations.value = locations
        applyFilters()
    }

    fun searchProducts(query: String, token: String) {
        if (query.isBlank()) {
            clearSearchResults()
            return
        }

        if (productRepository == null) {
            _errorMessage.value = "Search is not ready. Please try again."
            return
        }

        viewModelScope.launch {
            try {
                _isLoading.value = true
                _errorMessage.value = null

                val categoryId = _selectedCategoryId.value ?: 0
                val result = productRepository?.searchProducts(query, categoryId, token)

                if (result != null) {
                    result.onSuccess { products ->
                        _originalSearchResults.value = products
                        applyFilters()
                        _isLoading.value = false
                        addToLastSearches(query)
                    }
                    result.onFailure { exception ->
                        _errorMessage.value = exception.message
                        _isLoading.value = false
                    }
                } else {
                    _errorMessage.value = "Search failed. Please try again."
                    _isLoading.value = false
                }
            } catch (e: Exception) {
                _errorMessage.value = e.message
                _isLoading.value = false
            }
        }
    }

    fun loadPopularProducts(token: String) {
        viewModelScope.launch {
            try {
                _isLoading.value = true
                productRepository?.getAllProducts(token)?.onSuccess { products ->
                    _popularProducts.value = products.take(10)
                    if (_originalSearchResults.value.isNullOrEmpty()) {
                        _originalSearchResults.value = products
                        applyFilters()
                    }
                    _isLoading.value = false
                }?.onFailure { _isLoading.value = false }
            } catch (e: Exception) { _isLoading.value = false }
        }
    }

    private fun addToLastSearches(query: String) {
        val current = _lastSearchQueries.value?.toMutableList() ?: mutableListOf()
        if (query !in current) {
            current.add(0, query)
            if (current.size > 4) current.removeAt(current.size - 1)
            _lastSearchQueries.value = current
            viewModelScope.launch {
                DataStoreManager.saveSearchHistory(getApplication(), current)
            }
        }
    }

    fun clearLastSearches() {
        _lastSearchQueries.value = emptyList()
        viewModelScope.launch {
            DataStoreManager.saveSearchHistory(getApplication(), emptyList())
        }
    }

    fun removeLastSearch(query: String) {
        val current = _lastSearchQueries.value?.toMutableList() ?: mutableListOf()
        current.remove(query)
        _lastSearchQueries.value = current
        viewModelScope.launch {
            DataStoreManager.saveSearchHistory(getApplication(), current)
        }
    }

    fun setFilterPriceRange(minPrice: Int, maxPrice: Int) {
        _priceRange.value = Pair(minPrice, maxPrice)
        applyFilters()
    }

    fun setFilterColors(colors: List<String>) {
        _selectedColors.value = colors
        applyFilters()
    }

    fun resetAllFilters() {
        _selectedCategoryId.value = null
        _priceRange.value = null
        _selectedColors.value = emptyList()
        _selectedLocations.value = emptyList()
        applyFilters()
    }

    private fun applyFilters() {
        var result = _originalSearchResults.value ?: emptyList()

        _selectedCategoryId.value?.let { id -> if (id > 0) result = result.filter { it.category_id == id } }
        _priceRange.value?.let { (min, max) ->
            result = result.filter { product ->
                val price = product.getPrimaryPrice()
                price >= min.toDouble() && price <= max.toDouble()
            }
        }
        _selectedColors.value?.let { colors ->
            if (colors.isNotEmpty()) {
                result = result.filter { product ->
                    product.variants.any { v -> colors.any { c -> c.equals(v.color, true) } }
                }
            }
        }

        _searchResults.value = result
    }
}

package com.example.btl.ViewModel

import android.app.Application
import android.util.Log
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.viewModelScope
import com.example.btl.DataStore.DataStoreManager
import com.example.btl.Model.Product
import com.example.btl.Repository.ProductRepository
import kotlinx.coroutines.launch

class SearchViewModel(application: Application) : AndroidViewModel(application) {
    private var productRepository: ProductRepository? = null
    private val TAG = "SearchViewModel"

    private val _originalSearchResults = MutableLiveData<List<Product>>(emptyList())

    private val _searchResults = MutableLiveData<List<Product>>(emptyList())
    val searchResults: LiveData<List<Product>> = _searchResults

    private val _isLoading = MutableLiveData<Boolean>(false)
    val isLoading: LiveData<Boolean> = _isLoading

    private val _errorMessage = MutableLiveData<String?>(null)
    val errorMessage: LiveData<String?> = _errorMessage

    private val _lastSearchQueries = MutableLiveData<List<String>>(emptyList())
    val lastSearchQueries: LiveData<List<String>> = _lastSearchQueries

    private val _popularProducts = MutableLiveData<List<Product>>(emptyList())
    val popularProducts: LiveData<List<Product>> = _popularProducts

    private val _selectedCategoryId = MutableLiveData<Int?>(null)
    val selectedCategoryId: LiveData<Int?> = _selectedCategoryId

    private val _priceRange = MutableLiveData<Pair<Int, Int>?>(null)
    val priceRange: LiveData<Pair<Int, Int>?> = _priceRange

    private val _selectedColors = MutableLiveData<List<String>>(emptyList())
    val selectedColors: LiveData<List<String>> = _selectedColors

    private val _selectedLocations = MutableLiveData<List<String>>(emptyList())
    val selectedLocations: LiveData<List<String>> = _selectedLocations

    fun init() {
        if (productRepository == null) {
            productRepository = ProductRepository()
        }

        viewModelScope.launch {
            val history = DataStoreManager.getSearchHistory(getApplication())
            _lastSearchQueries.value = history
        }
    }

    /**
     * Xóa kết quả tìm kiếm hiện tại
     */
    fun clearSearchResults() {
        _originalSearchResults.value = emptyList()
        _searchResults.value = emptyList()
    }

    /**
     * Lọc theo địa điểm
     */
    fun setFilterLocations(locations: List<String>) {
        _selectedLocations.value = locations
        applyFilters()
    }

    fun searchProducts(query: String, token: String) {
        val normalizedQuery = query.trim()
        if (normalizedQuery.isBlank()) {
            clearSearchResults()
            return
        }

        // Save history immediately so failed searches still show up
        addToLastSearches(normalizedQuery)

        if (productRepository == null) {
            _errorMessage.value = "Search is not ready. Please try again."
            return
        }

        viewModelScope.launch {
            try {
                _isLoading.value = true
                _errorMessage.value = null

                val categoryId = _selectedCategoryId.value ?: 0
                val result = productRepository?.searchProducts(normalizedQuery, categoryId, token)

                if (result != null) {
                    result.onSuccess { products ->
                        _originalSearchResults.value = products
                        applyFilters()
                        _isLoading.value = false
                    }
                    result.onFailure { exception ->
                        _errorMessage.value = exception.message
                        _isLoading.value = false
                    }
                } else {
                    _errorMessage.value = "Search failed. Please try again."
                    _isLoading.value = false
                }
            } catch (e: Exception) {
                _errorMessage.value = e.message
                _isLoading.value = false
            }
        }
    }

    fun loadPopularProducts(token: String) {
        viewModelScope.launch {
            try {
                _isLoading.value = true
                productRepository?.getAllProducts(token)?.onSuccess { products ->
                    _popularProducts.value = products.take(10)
                    if (_originalSearchResults.value.isNullOrEmpty()) {
                        _originalSearchResults.value = products
                        applyFilters()
                    }
                    _isLoading.value = false
                }?.onFailure { _isLoading.value = false }
            } catch (e: Exception) { _isLoading.value = false }
        }
    }

    private fun addToLastSearches(query: String) {
        val normalizedQuery = query.trim()
        if (normalizedQuery.isBlank()) return

        val current = _lastSearchQueries.value?.toMutableList() ?: mutableListOf()
        val existingIndex = current.indexOfFirst { it.equals(normalizedQuery, ignoreCase = true) }
        if (existingIndex >= 0) {
            current.removeAt(existingIndex)
        }

        current.add(0, normalizedQuery)
        if (current.size > 4) current.removeAt(current.size - 1)
        _lastSearchQueries.value = current
        viewModelScope.launch {
            DataStoreManager.saveSearchHistory(getApplication(), current)
        }
    }

    fun clearLastSearches() {
        _lastSearchQueries.value = emptyList()
        viewModelScope.launch {
            DataStoreManager.saveSearchHistory(getApplication(), emptyList())
        }
    }

    fun removeLastSearch(query: String) {
        val current = _lastSearchQueries.value?.toMutableList() ?: mutableListOf()
        current.remove(query)
        _lastSearchQueries.value = current
        viewModelScope.launch {
            DataStoreManager.saveSearchHistory(getApplication(), current)
        }
    }

    fun setFilterPriceRange(minPrice: Int, maxPrice: Int) {
        _priceRange.value = Pair(minPrice, maxPrice)
        applyFilters()
    }

    fun setFilterColors(colors: List<String>) {
        _selectedColors.value = colors
        applyFilters()
    }

    fun resetAllFilters() {
        _selectedCategoryId.value = null
        _priceRange.value = null
        _selectedColors.value = emptyList()
        _selectedLocations.value = emptyList()
        applyFilters()
    }

    private fun applyFilters() {
        var result = _originalSearchResults.value ?: emptyList()

        _selectedCategoryId.value?.let { id -> if (id > 0) result = result.filter { it.category_id == id } }
        _priceRange.value?.let { (min, max) ->
            result = result.filter { product ->
                val price = product.getPrimaryPrice()
                price >= min.toDouble() && price <= max.toDouble()
            }
        }
        _selectedColors.value?.let { colors ->
            if (colors.isNotEmpty()) {
                result = result.filter { product ->
                    product.variants.any { v -> colors.any { c -> c.equals(v.color, true) } }
                }
            }
        }

        _searchResults.value = result
    }
}
